import{c as a,Q as t,j as o,m as r}from"./chunks/framework.rlpw0eGz.js";const u=JSON.parse('{"title":"Browser Use 与 Computer Use","description":"","frontmatter":{},"headers":[],"relativePath":"zh/getting-started/browser-computer-use.md","filePath":"zh/getting-started/browser-computer-use.md","lastUpdated":1779274370000}'),s={name:"zh/getting-started/browser-computer-use.md"};function d(c,e,i,l,p,n){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="browser-use-与-computer-use" tabindex="-1">Browser Use 与 Computer Use <a class="header-anchor" href="#browser-use-与-computer-use" aria-label="Permalink to &quot;Browser Use 与 Computer Use&quot;">​</a></h1><p>Memoh 可以在机器人 workspace 容器里启动一个可见桌面和有头浏览器。这和跑 headless Playwright 脚本不是一条路径：机器人操作的是网页端 Display pane 里也能看到的那套图形浏览器。</p><h2 id="概念区别" tabindex="-1">概念区别 <a class="header-anchor" href="#概念区别" aria-label="Permalink to &quot;概念区别&quot;">​</a></h2><table tabindex="0"><thead><tr><th>能力</th><th>适合</th><th>工作方式</th></tr></thead><tbody><tr><td>Headless browser 命令</td><td>快速脚本化网页自动化</td><td>在 workspace 里正常运行 Playwright 或其它浏览器工具。</td></tr><tr><td>Browser Use</td><td>网页、表单、导航、截图、可访问性树检查</td><td>通过 CDP 操作 workspace 里的有头 Chrome/Chromium。</td></tr><tr><td>Computer Use</td><td>原生弹窗、浏览器状态坏掉、非浏览器 GUI</td><td>读取桌面无障碍树（AT-SPI）拿到 ref，无法解析时回退到坐标与截图。</td></tr></tbody></table><p>网页内操作优先用 Browser Use。只有遇到 CDP 够不到的 GUI 状态时，再用 Computer Use。</p><h2 id="workspace-display-与-vnc" tabindex="-1">Workspace display 与 VNC <a class="header-anchor" href="#workspace-display-与-vnc" aria-label="Permalink to &quot;Workspace display 与 VNC&quot;">​</a></h2><p>Workspace display 是机器人 workspace 容器里的桌面环境。VNC/RFB 是这套桌面的显示和输入传输基础；网页端的 Display 会话使用 WebRTC 承载画面。</p><p>重点不是“有 VNC”本身，而是 workspace 能跑有头 Chrome/Chromium。很多登录、验证码、复杂前端状态或只支持真实图形会话的网站，headless 模式不一定可靠。</p><h2 id="准备机器人桌面" tabindex="-1">准备机器人桌面 <a class="header-anchor" href="#准备机器人桌面" aria-label="Permalink to &quot;准备机器人桌面&quot;">​</a></h2><ol><li>打开机器人详情页。</li><li>进入 <strong>Desktop</strong> tab。</li><li>准备或启用 workspace display runtime。</li><li>从机器人设置页或聊天 workspace 打开 display session。</li></ol><p>Display runtime 会安装或使用桌面、VNC server、浏览器和字体等组件。具体可用性取决于 workspace backend 和镜像。</p><h2 id="agent-工具" tabindex="-1">Agent 工具 <a class="header-anchor" href="#agent-工具" aria-label="Permalink to &quot;Agent 工具&quot;">​</a></h2><p>workspace desktop 启用后，agent 可以使用浏览器和电脑操作工具：</p><ul><li><code>browser_observe</code> 检查当前浏览器页面（snapshot、get_content、screenshot、evaluate 等）。</li><li><code>browser_action</code> 在有头浏览器里点击、填表、输入、按键、导航。</li><li><code>browser_remote_session</code> 暴露浏览器 CDP endpoint，给代码驱动的会话使用。</li><li><code>computer_observe</code> 返回桌面无障碍树快照（ref 如 <code>e3</code>）或者一张落盘截图的路径。</li><li><code>computer_action</code> 操作桌面：优先使用快照里的 <code>ref</code>；当 ref 不可用或无障碍调用失败时回退到 <code>(x, y)</code> 坐标。</li></ul><h3 id="截图不再自动注入对话" tabindex="-1">截图不再自动注入对话 <a class="header-anchor" href="#截图不再自动注入对话" aria-label="Permalink to &quot;截图不再自动注入对话&quot;">​</a></h3><p><code>browser_observe</code> 与 <code>computer_observe</code> 的截图会落盘到 workspace 路径（如 <code>/data/computer-screenshots/1716200000.jpg</code>），工具结果只返回这个路径，不再自动塞到对话里。需要查看图像时显式调用文件读取工具读这个路径，可以让观察成本变低，也把“是否值得花 token 读图”交回模型决定。</p><h3 id="无障碍辅助二进制" tabindex="-1">无障碍辅助二进制 <a class="header-anchor" href="#无障碍辅助二进制" aria-label="Permalink to &quot;无障碍辅助二进制&quot;">​</a></h3><p>Computer Use 依赖容器内 <code>/opt/memoh/toolkit/display/bin/a11y-cli</code> 以及 workspace 的 <code>at-spi2-core</code> 包。Display runtime probe 会返回 <code>a11y_available</code>，便于 Web UI 显示无障碍路径是否健康。AT-SPI 不可用时，<code>computer_action</code> 仍可用坐标驱动，<code>computer_observe screenshot</code> 仍然可用。</p><p>这些是 workspace runtime 能力，不是用来自动化 Electron 桌面 App 本身的。</p><h2 id="相关页面" tabindex="-1">相关页面 <a class="header-anchor" href="#相关页面" aria-label="Permalink to &quot;相关页面&quot;">​</a></h2><ul><li><a href="/zh/getting-started/container.html">容器与 Workspace</a></li><li><a href="/zh/installation/workspace-backends.html">Workspace backend</a></li></ul>',21)])])}const m=a(s,[["render",d]]);export{u as __pageData,m as default};
